import "sort"

type UnionFind struct {
	parent []int64
	rank   []int64
}

func NewUnionFind(n int64) *UnionFind {
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}
	return &UnionFind{parent, rank}
}

func (uf *UnionFind) Find(u int64) int64 {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int64) bool {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU == rootV {
		return false
	}
	if uf.rank[rootU] > uf.rank[rootV] {
		uf.parent[rootV] = rootU
	} else if uf.rank[rootU] < uf.rank[rootV] {
		uf.parent[rootU] = rootV
	} else {
		uf.parent[rootV] = rootU
		uf.rank[rootU]++
	}
	return true
}

func solve(n int64, edges [][]int64, k int64) int64 {
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})

	uf := NewUnionFind(n)
	components := n
	res := int64(0)

	for _, edge := range edges {
		if components <= k {
			break
		}
		u, v, w := edge[0], edge[1], edge[2]
		if uf.Union(u, v) {
			components--
			res = w
		}
	}

	return res
}
