func solve(n int64, edges [][]int64, k int64) int64 {
    nInt := int(n)
    low := int64(0)
    high := int64(1000000)

    for low < high {
        mid := (low + high) / 2
        parent := make([]int, nInt)
        rank := make([]int, nInt)
        for i := 0; i < nInt; i++ {
            parent[i] = i
            rank[i] = 0
        }

        find := func(x int) int {
            ori := x
            for parent[x] != x {
                x = parent[x]
            }
            root := x
            x = ori
            for parent[x] != root {
                next := parent[x]
                parent[x] = root
                x = next
            }
            return root
        }

        for _, edge := range edges {
            w := edge[2]
            if w <= mid {
                u := int(edge[0])
                v := int(edge[1])
                ru := find(u)
                rv := find(v)
                if ru == rv {
                    continue
                }
                if rank[ru] < rank[rv] {
                    parent[ru] = rv
                } else if rank[ru] > rank[rv] {
                    parent[rv] = ru
                } else {
                    parent[rv] = ru
                    rank[ru]++
                }
            }
        }

        compMap := make(map[int]bool)
        for i := 0; i < nInt; i++ {
            r := find(i)
            compMap[r] = true
        }
        compCount := len(compMap)

        if compCount <= int(k) {
            high = mid
        } else {
            low = mid + 1
        }
    }

    return low
}
